external_knowledge:
- A "data ingestion champion" refers to the user(s) who have ingested the most records from their preferred external data sources; 
- Ingesting records implies retrieving or collecting data from the preferred external data sources; 
- Preferred data sources are those that the user has indicated a preference for.

sql:
SELECT
    (SELECT AVG(reliability_score) FROM financial_indicators) AS avg_reliability_score,
    (SELECT COUNT(*) FROM access_logs WHERE user_id = 1) AS total_access_events;

SELECT date, close_price 
FROM historical_prices
WHERE price_id = 1;

SELECT ticker, name, COUNT(*) OVER () AS total_technology_securities
FROM securities
WHERE sector = 'Technology';
